40: const (
41: 	DefaultSegmentSize = 128 * 1024 * 1024 // DefaultSegmentSize is 128 MB.
42: 	pageSize           = 32 * 1024         // pageSize is 32KB.
43: 	recordHeaderSize   = 7
44: 	WblDirName         = "wbl"
45: )
46: 
47: // The table gets initialized with sync.Once but may still cause a race
48: // with any other use of the crc32 package anywhere. Thus we initialize it
49: // before.
50: var castagnoliTable = crc32.MakeTable(crc32.Castagnoli)
51: 
52: // page is an in memory buffer used to batch disk writes.
53: // Records bigger than the page size are split and flushed separately.
54: // A flush is triggered when a single records doesn't fit the page size or
55: // when the next record can't fit in the remaining free page space.
56: type page struct {
57: 	alloc   int
58: 	flushed int
59: 	buf     [pageSize]byte
60: }
61: 
62: func (p *page) remaining() int {
63: 	return pageSize - p.alloc
64: }
65: 
66: func (p *page) full() bool {
67: 	return pageSize-p.alloc < recordHeaderSize
68: }
69: 
70: func (p *page) reset() {
71: 	for i := range p.buf {
72: 		p.buf[i] = 0
73: 	}
74: 	p.alloc = 0
75: 	p.flushed = 0
76: }
77: 
78: // SegmentFile represents the underlying file used to store a segment.
79: type SegmentFile interface {
80: 	Stat() (os.FileInfo, error)
81: 	Sync() error
82: 	io.Writer
83: 	io.Reader
84: 	io.Closer
85: }
86: 
87: // Segment represents a segment file.
88: type Segment struct {
89: 	SegmentFile
90: 	dir string
91: 	i   int
92: }
93: 
94: // Index returns the index of the segment.
95: func (s *Segment) Index() int {
96: 	return s.i
97: }
98: 
99: // Dir returns the directory of the segment.
100: func (s *Segment) Dir() string {
101: 	return s.dir
102: }
103: 
104: // CorruptionErr is an error that's returned when corruption is encountered.
105: type CorruptionErr struct {
106: 	Dir     string
107: 	Segment int
108: 	Offset  int64
109: 	Err     error
110: }
111: 
112: func (e *CorruptionErr) Error() string {
113: 	if e.Segment < 0 {
114: 		return fmt.Sprintf("corruption after %d bytes: %s", e.Offset, e.Err)
115: 	}
116: 	return fmt.Sprintf("corruption in segment %s at %d: %s", SegmentName(e.Dir, e.Segment), e.Offset, e.Err)
117: }
118: 
119: func (e *CorruptionErr) Unwrap() error {
120: 	return e.Err
121: }
122: 
123: // OpenWriteSegment opens segment k in dir. The returned segment is ready for new appends.
124: func OpenWriteSegment(logger *slog.Logger, dir string, k int) (*Segment, error) {
125: 	segName := SegmentName(dir, k)
126: 	f, err := os.OpenFile(segName, os.O_WRONLY|os.O_APPEND, 0o666)
127: 	if err != nil {
128: 		return nil, err
129: 	}
130: 	stat, err := f.Stat()
131: 	if err != nil {
132: 		f.Close()
133: 		return nil, err
134: 	}
135: 	// If the last page is torn, fill it with zeros.
136: 	// In case it was torn after all records were written successfully, this
137: 	// will just pad the page and everything will be fine.
138: 	// If it was torn mid-record, a full read (which the caller should do anyway
139: 	// to ensure integrity) will detect it as a corruption by the end.
140: 	if d := stat.Size() % pageSize; d != 0 {
141: 		logger.Warn("Last page of the wlog is torn, filling it with zeros", "segment", segName)
142: 		if _, err := f.Write(make([]byte, pageSize-d)); err != nil {
143: 			f.Close()
144: 			return nil, fmt.Errorf("zero-pad torn page: %w", err)
145: 		}
146: 	}
147: 	return &Segment{SegmentFile: f, i: k, dir: dir}, nil
148: }
149: 
150: // CreateSegment creates a new segment k in dir.
151: func CreateSegment(dir string, k int) (*Segment, error) {
152: 	f, err := os.OpenFile(SegmentName(dir, k), os.O_WRONLY|os.O_CREATE|os.O_APPEND, 0o666)
153: 	if err != nil {
154: 		return nil, err
155: 	}
156: 	return &Segment{SegmentFile: f, i: k, dir: dir}, nil
157: }
158: 
159: // OpenReadSegment opens the segment with the given filename.
160: func OpenReadSegment(fn string) (*Segment, error) {
161: 	k, err := strconv.Atoi(filepath.Base(fn))
162: 	if err != nil {
163: 		return nil, errors.New("not a valid filename")
164: 	}
165: 	f, err := os.Open(fn)
166: 	if err != nil {
167: 		return nil, err
168: 	}
169: 	return &Segment{SegmentFile: f, i: k, dir: filepath.Dir(fn)}, nil
170: }
