875: // Segments returns the range [first, n] of currently existing segments.
876: // If no segments are found, first and n are -1.
877: func Segments(wlDir string) (first, last int, err error) {
878: 	refs, err := listSegments(wlDir)
879: 	if err != nil {
880: 		return 0, 0, err
881: 	}
882: 	if len(refs) == 0 {
883: 		return -1, -1, nil
884: 	}
885: 	return refs[0].index, refs[len(refs)-1].index, nil
886: }
887: 
888: type segmentRef struct {
889: 	name  string
890: 	index int
891: }
892: 
893: func listSegments(dir string) (refs []segmentRef, err error) {
894: 	files, err := os.ReadDir(dir)
895: 	if err != nil {
896: 		return nil, err
897: 	}
898: 	for _, f := range files {
899: 		fn := f.Name()
900: 		k, err := strconv.Atoi(fn)
901: 		if err != nil {
902: 			continue
903: 		}
904: 		refs = append(refs, segmentRef{name: fn, index: k})
905: 	}
906: 	slices.SortFunc(refs, func(a, b segmentRef) int {
907: 		return a.index - b.index
908: 	})
909: 	for i := 0; i < len(refs)-1; i++ {
910: 		if refs[i].index+1 != refs[i+1].index {
911: 			return nil, errors.New("segments are not sequential")
912: 		}
913: 	}
914: 	return refs, nil
915: }
916: 
917: // SegmentRange groups segments by the directory and the first and last index it includes.
918: type SegmentRange struct {
919: 	Dir         string
920: 	First, Last int
921: }
922: 
923: // NewSegmentsReader returns a new reader over all segments in the directory.
924: func NewSegmentsReader(dir string) (io.ReadCloser, error) {
925: 	return NewSegmentsRangeReader(SegmentRange{dir, -1, -1})
926: }
927: 
928: // NewSegmentsRangeReader returns a new reader over the given WAL segment ranges.
929: // If first or last are -1, the range is open on the respective end.
930: func NewSegmentsRangeReader(sr ...SegmentRange) (io.ReadCloser, error) {
931: 	var segs []*Segment
932: 
933: 	for _, sgmRange := range sr {
934: 		refs, err := listSegments(sgmRange.Dir)
935: 		if err != nil {
936: 			return nil, fmt.Errorf("list segment in dir:%v: %w", sgmRange.Dir, err)
937: 		}
938: 
939: 		for _, r := range refs {
940: 			if sgmRange.First >= 0 && r.index < sgmRange.First {
941: 				continue
942: 			}
943: 			if sgmRange.Last >= 0 && r.index > sgmRange.Last {
944: 				break
945: 			}
946: 			s, err := OpenReadSegment(filepath.Join(sgmRange.Dir, r.name))
947: 			if err != nil {
948: 				return nil, fmt.Errorf("open segment:%v in dir:%v: %w", r.name, sgmRange.Dir, err)
949: 			}
950: 			segs = append(segs, s)
951: 		}
952: 	}
953: 	return NewSegmentBufReader(segs...), nil
954: }
955: 
956: // segmentBufReader is a buffered reader that reads in multiples of pages.
957: // The main purpose is that we are able to track segment and offset for
958: // corruption reporting.  We have to be careful not to increment curr too
959: // early, as it is used by Reader.Err() to tell Repair which segment is corrupt.
960: // As such we pad the end of non-page align segments with zeros.
961: type segmentBufReader struct {
962: 	buf  *bufio.Reader
963: 	segs []*Segment
964: 	cur  int // Index into segs.
965: 	off  int // Offset of read data into current segment.
966: }
967: 
968: func NewSegmentBufReader(segs ...*Segment) io.ReadCloser {
969: 	if len(segs) == 0 {
970: 		return &segmentBufReader{}
971: 	}
972: 
973: 	return &segmentBufReader{
974: 		buf:  bufio.NewReaderSize(segs[0], 16*pageSize),
975: 		segs: segs,
976: 	}
977: }
978: 
979: func NewSegmentBufReaderWithOffset(offset int, segs ...*Segment) (io.ReadCloser, error) {
980: 	if offset == 0 || len(segs) == 0 {
981: 		return NewSegmentBufReader(segs...), nil
982: 	}
983: 
984: 	sbr := &segmentBufReader{
985: 		buf:  bufio.NewReaderSize(segs[0], 16*pageSize),
986: 		segs: segs,
987: 	}
988: 	var err error
989: 	if offset > 0 {
990: 		_, err = sbr.buf.Discard(offset)
991: 	}
992: 	return sbr, err
993: }
994: 
995: func (r *segmentBufReader) Close() (err error) {
996: 	for _, s := range r.segs {
997: 		if e := s.Close(); e != nil {
998: 			err = e
999: 		}
1000: 	}
1001: 	return err
1002: }
1003: 
1004: // Read implements io.Reader.
1005: func (r *segmentBufReader) Read(b []byte) (n int, err error) {
1006: 	if len(r.segs) == 0 {
1007: 		return 0, io.EOF
1008: 	}
1009: 
1010: 	n, err = r.buf.Read(b)
1011: 	r.off += n
1012: 
1013: 	// If we succeeded, or hit a non-EOF, we can stop.
1014: 	if err == nil || !errors.Is(err, io.EOF) {
1015: 		return n, err
1016: 	}
1017: 
1018: 	// We hit EOF; fake out zero padding at the end of short segments, so we
1019: 	// don't increment curr too early and report the wrong segment as corrupt.
1020: 	if r.off%pageSize != 0 {
1021: 		i := 0
1022: 		for ; n+i < len(b) && (r.off+i)%pageSize != 0; i++ {
1023: 			b[n+i] = 0
1024: 		}
1025: 
1026: 		// Return early, even if we didn't fill b.
1027: 		r.off += i
1028: 		return n + i, nil
1029: 	}
1030: 
1031: 	// There is no more deta left in the curr segment and there are no more
1032: 	// segments left.  Return EOF.
1033: 	if r.cur+1 >= len(r.segs) {
1034: 		return n, io.EOF
1035: 	}
1036: 
1037: 	// Move to next segment.
1038: 	r.cur++
1039: 	r.off = 0
1040: 	r.buf.Reset(r.segs[r.cur])
1041: 	return n, nil
1042: }
