216: // Type returns the type of the record.
217: // Returns RecordUnknown if no valid record type is found.
218: func (*Decoder) Type(rec []byte) Type {
219: 	if len(rec) < 1 {
220: 		return Unknown
221: 	}
222: 	switch t := Type(rec[0]); t {
223: 	case Series, Samples, Tombstones, Exemplars, MmapMarkers, Metadata, HistogramSamples, FloatHistogramSamples, CustomBucketsHistogramSamples, CustomBucketsFloatHistogramSamples:
224: 		return t
225: 	}
226: 	return Unknown
227: }
