229: // Series appends series in rec to the given slice.
230: func (d *Decoder) Series(rec []byte, series []RefSeries) ([]RefSeries, error) {
231: 	dec := encoding.Decbuf{B: rec}
232: 
233: 	if Type(dec.Byte()) != Series {
234: 		return nil, errors.New("invalid record type")
235: 	}
236: 	for len(dec.B) > 0 && dec.Err() == nil {
237: 		ref := storage.SeriesRef(dec.Be64())
238: 		lset := d.DecodeLabels(&dec)
239: 
240: 		series = append(series, RefSeries{
241: 			Ref:    chunks.HeadSeriesRef(ref),
242: 			Labels: lset,
243: 		})
244: 	}
245: 	if dec.Err() != nil {
246: 		return nil, dec.Err()
247: 	}
248: 	if len(dec.B) > 0 {
249: 		return nil, fmt.Errorf("unexpected %d bytes left in entry", len(dec.B))
250: 	}
251: 	return series, nil
252: }
