254: // Metadata appends metadata in rec to the given slice.
255: func (*Decoder) Metadata(rec []byte, metadata []RefMetadata) ([]RefMetadata, error) {
256: 	dec := encoding.Decbuf{B: rec}
257: 
258: 	if Type(dec.Byte()) != Metadata {
259: 		return nil, errors.New("invalid record type")
260: 	}
261: 	for len(dec.B) > 0 && dec.Err() == nil {
262: 		ref := dec.Uvarint64()
263: 		typ := dec.Byte()
264: 		numFields := dec.Uvarint()
265: 
266: 		// We're currently aware of two more metadata fields other than TYPE; that is UNIT and HELP.
267: 		// We can skip the rest of the fields (if we encounter any), but we must decode them anyway
268: 		// so we can correctly align with the start with the next metadata record.
269: 		var unit, help string
270: 		for range numFields {
271: 			fieldName := dec.UvarintStr()
272: 			fieldValue := dec.UvarintStr()
273: 			switch fieldName {
274: 			case unitMetaName:
275: 				unit = fieldValue
276: 			case helpMetaName:
277: 				help = fieldValue
278: 			}
279: 		}
280: 
281: 		metadata = append(metadata, RefMetadata{
282: 			Ref:  chunks.HeadSeriesRef(ref),
283: 			Type: typ,
284: 			Unit: unit,
285: 			Help: help,
286: 		})
287: 	}
288: 	if dec.Err() != nil {
289: 		return nil, dec.Err()
290: 	}
291: 	if len(dec.B) > 0 {
292: 		return nil, fmt.Errorf("unexpected %d bytes left in entry", len(dec.B))
293: 	}
294: 	return metadata, nil
295: }
