301: // DecodeLabels decodes one set of labels from buf.
302: func (d *Decoder) DecodeLabels(dec *encoding.Decbuf) labels.Labels {
303: 	d.builder.Reset()
304: 	nLabels := dec.Uvarint()
305: 	for range nLabels {
306: 		lName := dec.UvarintBytes()
307: 		lValue := dec.UvarintBytes()
308: 		d.builder.Add(yoloString(lName), yoloString(lValue))
309: 	}
310: 	return d.builder.Labels()
311: }
