313: // Samples appends samples in rec to the given slice.
314: func (*Decoder) Samples(rec []byte, samples []RefSample) ([]RefSample, error) {
315: 	dec := encoding.Decbuf{B: rec}
316: 
317: 	if Type(dec.Byte()) != Samples {
318: 		return nil, errors.New("invalid record type")
319: 	}
320: 	if dec.Len() == 0 {
321: 		return samples, nil
322: 	}
323: 	var (
324: 		baseRef  = dec.Be64()
325: 		baseTime = dec.Be64int64()
326: 	)
327: 	// Allow 1 byte for each varint and 8 for the value; the output slice must be at least that big.
328: 	if minSize := dec.Len() / (1 + 1 + 8); cap(samples) < minSize {
329: 		samples = make([]RefSample, 0, minSize)
330: 	}
331: 	for len(dec.B) > 0 && dec.Err() == nil {
332: 		dref := dec.Varint64()
333: 		dtime := dec.Varint64()
334: 		val := dec.Be64()
335: 
336: 		samples = append(samples, RefSample{
337: 			Ref: chunks.HeadSeriesRef(int64(baseRef) + dref),
338: 			T:   baseTime + dtime,
339: 			V:   math.Float64frombits(val),
340: 		})
341: 	}
342: 
343: 	if dec.Err() != nil {
344: 		return nil, fmt.Errorf("decode error after %d samples: %w", len(samples), dec.Err())
345: 	}
346: 	if len(dec.B) > 0 {
347: 		return nil, fmt.Errorf("unexpected %d bytes left in entry", len(dec.B))
348: 	}
349: 	return samples, nil
350: }
