445: func (d *Decoder) HistogramSamples(rec []byte, histograms []RefHistogramSample) ([]RefHistogramSample, error) {
446: 	dec := encoding.Decbuf{B: rec}
447: 	t := Type(dec.Byte())
448: 	if t != HistogramSamples && t != CustomBucketsHistogramSamples {
449: 		return nil, errors.New("invalid record type")
450: 	}
451: 	if dec.Len() == 0 {
452: 		return histograms, nil
453: 	}
454: 	var (
455: 		baseRef  = dec.Be64()
456: 		baseTime = dec.Be64int64()
457: 	)
458: 	for len(dec.B) > 0 && dec.Err() == nil {
459: 		dref := dec.Varint64()
460: 		dtime := dec.Varint64()
461: 
462: 		rh := RefHistogramSample{
463: 			Ref: chunks.HeadSeriesRef(baseRef + uint64(dref)),
464: 			T:   baseTime + dtime,
465: 			H:   &histogram.Histogram{},
466: 		}
467: 
468: 		DecodeHistogram(&dec, rh.H)
469: 
470: 		if !histogram.IsKnownSchema(rh.H.Schema) {
471: 			d.logger.Warn("skipping histogram with unknown schema in WAL record", "schema", rh.H.Schema, "timestamp", rh.T)
472: 			continue
473: 		}
474: 		if rh.H.Schema > histogram.ExponentialSchemaMax && rh.H.Schema <= histogram.ExponentialSchemaMaxReserved {
475: 			// This is a very slow path, but it should only happen if the
476: 			// record is from a newer Prometheus version that supports higher
477: 			// resolution.
478: 			if err := rh.H.ReduceResolution(histogram.ExponentialSchemaMax); err != nil {
479: 				return nil, fmt.Errorf("error reducing resolution of histogram #%d: %w", len(histograms)+1, err)
480: 			}
481: 		}
482: 
483: 		histograms = append(histograms, rh)
484: 	}
485: 
486: 	if dec.Err() != nil {
487: 		return nil, fmt.Errorf("decode error after %d histograms: %w", len(histograms), dec.Err())
488: 	}
489: 	if len(dec.B) > 0 {
490: 		return nil, fmt.Errorf("unexpected %d bytes left in entry", len(dec.B))
491: 	}
492: 	return histograms, nil
493: }
