495: // DecodeHistogram decodes a Histogram from a byte slice.
496: func DecodeHistogram(buf *encoding.Decbuf, h *histogram.Histogram) {
497: 	h.CounterResetHint = histogram.CounterResetHint(buf.Byte())
498: 
499: 	h.Schema = int32(buf.Varint64())
500: 	h.ZeroThreshold = math.Float64frombits(buf.Be64())
501: 
502: 	h.ZeroCount = buf.Uvarint64()
503: 	h.Count = buf.Uvarint64()
504: 	h.Sum = math.Float64frombits(buf.Be64())
505: 
506: 	l := buf.Uvarint()
507: 	if l > 0 {
508: 		h.PositiveSpans = make([]histogram.Span, l)
509: 	}
510: 	for i := range h.PositiveSpans {
511: 		h.PositiveSpans[i].Offset = int32(buf.Varint64())
512: 		h.PositiveSpans[i].Length = buf.Uvarint32()
513: 	}
514: 
515: 	l = buf.Uvarint()
516: 	if l > 0 {
517: 		h.NegativeSpans = make([]histogram.Span, l)
518: 	}
519: 	for i := range h.NegativeSpans {
520: 		h.NegativeSpans[i].Offset = int32(buf.Varint64())
521: 		h.NegativeSpans[i].Length = buf.Uvarint32()
522: 	}
523: 
524: 	l = buf.Uvarint()
525: 	if l > 0 {
526: 		h.PositiveBuckets = make([]int64, l)
527: 	}
528: 	for i := range h.PositiveBuckets {
529: 		h.PositiveBuckets[i] = buf.Varint64()
530: 	}
531: 
532: 	l = buf.Uvarint()
533: 	if l > 0 {
534: 		h.NegativeBuckets = make([]int64, l)
535: 	}
536: 	for i := range h.NegativeBuckets {
537: 		h.NegativeBuckets[i] = buf.Varint64()
538: 	}
539: 
540: 	if histogram.IsCustomBucketsSchema(h.Schema) {
541: 		l = buf.Uvarint()
542: 		if l > 0 {
543: 			h.CustomValues = make([]float64, l)
544: 		}
545: 		for i := range h.CustomValues {
546: 			h.CustomValues[i] = buf.Be64Float64()
547: 		}
548: 	}
549: }
