661: // Series appends the encoded series to b and returns the resulting slice.
662: func (*Encoder) Series(series []RefSeries, b []byte) []byte {
663: 	buf := encoding.Encbuf{B: b}
664: 	buf.PutByte(byte(Series))
665: 
666: 	for _, s := range series {
667: 		buf.PutBE64(uint64(s.Ref))
668: 		EncodeLabels(&buf, s.Labels)
669: 	}
670: 	return buf.Get()
671: }
672: 
673: // Metadata appends the encoded metadata to b and returns the resulting slice.
674: func (*Encoder) Metadata(metadata []RefMetadata, b []byte) []byte {
675: 	buf := encoding.Encbuf{B: b}
676: 	buf.PutByte(byte(Metadata))
677: 
678: 	for _, m := range metadata {
679: 		buf.PutUvarint64(uint64(m.Ref))
680: 
681: 		buf.PutByte(m.Type)
682: 
683: 		buf.PutUvarint(2) // num_fields: We currently have two more metadata fields, UNIT and HELP.
684: 		buf.PutUvarintStr(unitMetaName)
685: 		buf.PutUvarintStr(m.Unit)
686: 		buf.PutUvarintStr(helpMetaName)
687: 		buf.PutUvarintStr(m.Help)
688: 	}
689: 
690: 	return buf.Get()
691: }
