842: // EncodeHistogram encodes a Histogram into a byte slice.
843: func EncodeHistogram(buf *encoding.Encbuf, h *histogram.Histogram) {
844: 	buf.PutByte(byte(h.CounterResetHint))
845: 
846: 	buf.PutVarint64(int64(h.Schema))
847: 	buf.PutBE64(math.Float64bits(h.ZeroThreshold))
848: 
849: 	buf.PutUvarint64(h.ZeroCount)
850: 	buf.PutUvarint64(h.Count)
851: 	buf.PutBE64(math.Float64bits(h.Sum))
852: 
853: 	buf.PutUvarint(len(h.PositiveSpans))
854: 	for _, s := range h.PositiveSpans {
855: 		buf.PutVarint64(int64(s.Offset))
856: 		buf.PutUvarint32(s.Length)
857: 	}
858: 
859: 	buf.PutUvarint(len(h.NegativeSpans))
860: 	for _, s := range h.NegativeSpans {
861: 		buf.PutVarint64(int64(s.Offset))
862: 		buf.PutUvarint32(s.Length)
863: 	}
864: 
865: 	buf.PutUvarint(len(h.PositiveBuckets))
866: 	for _, b := range h.PositiveBuckets {
867: 		buf.PutVarint64(b)
868: 	}
869: 
870: 	buf.PutUvarint(len(h.NegativeBuckets))
871: 	for _, b := range h.NegativeBuckets {
872: 		buf.PutVarint64(b)
873: 	}
874: 
875: 	if histogram.IsCustomBucketsSchema(h.Schema) {
876: 		buf.PutUvarint(len(h.CustomValues))
877: 		for _, v := range h.CustomValues {
878: 			buf.PutBEFloat64(v)
879: 		}
880: 	}
881: }
