38: // CheckpointStats returns stats about a created checkpoint.
39: type CheckpointStats struct {
40: 	DroppedSeries     int
41: 	DroppedSamples    int // Includes histograms.
42: 	DroppedTombstones int
43: 	DroppedExemplars  int
44: 	DroppedMetadata   int
45: 	TotalSeries       int // Processed series including dropped ones.
46: 	TotalSamples      int // Processed float and histogram samples including dropped ones.
47: 	TotalTombstones   int // Processed tombstones including dropped ones.
48: 	TotalExemplars    int // Processed exemplars including dropped ones.
49: 	TotalMetadata     int // Processed metadata including dropped ones.
50: }
51: 
52: // LastCheckpoint returns the directory name and index of the most recent checkpoint.
53: // If dir does not contain any checkpoints, ErrNotFound is returned.
54: func LastCheckpoint(dir string) (string, int, error) {
55: 	checkpoints, err := listCheckpoints(dir)
56: 	if err != nil {
57: 		return "", 0, err
58: 	}
59: 
60: 	if len(checkpoints) == 0 {
61: 		return "", 0, record.ErrNotFound
62: 	}
63: 
64: 	checkpoint := checkpoints[len(checkpoints)-1]
65: 	return filepath.Join(dir, checkpoint.name), checkpoint.index, nil
66: }
67: 
68: // DeleteCheckpoints deletes all checkpoints in a directory below a given index.
69: func DeleteCheckpoints(dir string, maxIndex int) error {
70: 	checkpoints, err := listCheckpoints(dir)
71: 	if err != nil {
72: 		return err
73: 	}
74: 
75: 	var errs []error
76: 	for _, checkpoint := range checkpoints {
77: 		if checkpoint.index >= maxIndex {
78: 			break
79: 		}
80: 		errs = append(errs, os.RemoveAll(filepath.Join(dir, checkpoint.name)))
81: 	}
82: 	return errors.Join(errs...)
83: }
84: 
85: // checkpointTempFileSuffix is the suffix used when creating temporary checkpoint files.
86: const checkpointTempFileSuffix = ".tmp"
87: 
88: // DeleteTempCheckpoints deletes all temporary checkpoint directories in the given directory.
89: func DeleteTempCheckpoints(logger *slog.Logger, dir string) error {
90: 	if err := tsdbutil.RemoveTmpDirs(logger, dir, isTempDir); err != nil {
91: 		return fmt.Errorf("remove previous temporary checkpoint dirs: %w", err)
92: 	}
93: 	return nil
94: }
95: 
96: // Checkpoint creates a compacted checkpoint of segments in range [from, to] in the given WAL.
97: // It includes the most recent checkpoint if it exists.
98: // All series not satisfying keep, samples/tombstones/exemplars below mint and
99: // metadata that are not the latest are dropped.
100: //
101: // The checkpoint is stored in a directory named checkpoint.N in the same
102: // segmented format as the original WAL itself.
103: // This makes it easy to read it through the WAL package and concatenate
104: // it with the original WAL.
105: func Checkpoint(logger *slog.Logger, w *WL, from, to int, keep func(id chunks.HeadSeriesRef) bool, mint int64) (*CheckpointStats, error) {
106: 	stats := &CheckpointStats{}
107: 	var sgmReader io.ReadCloser
108: 
109: 	logger.Info("Creating checkpoint", "from_segment", from, "to_segment", to, "mint", mint)
110: 
111: 	{
112: 		var sgmRange []SegmentRange
113: 		dir, idx, err := LastCheckpoint(w.Dir())
114: 		if err != nil && !errors.Is(err, record.ErrNotFound) {
115: 			return nil, fmt.Errorf("find last checkpoint: %w", err)
116: 		}
117: 		last := idx + 1
118: 		if err == nil {
119: 			if from > last {
120: 				return nil, fmt.Errorf("unexpected gap to last checkpoint. expected:%v, requested:%v", last, from)
121: 			}
122: 			// Ignore WAL files below the checkpoint. They shouldn't exist to begin with.
123: 			from = last
124: 
125: 			sgmRange = append(sgmRange, SegmentRange{Dir: dir, Last: math.MaxInt32})
126: 		}
127: 
128: 		sgmRange = append(sgmRange, SegmentRange{Dir: w.Dir(), First: from, Last: to})
129: 		sgmReader, err = NewSegmentsRangeReader(sgmRange...)
130: 		if err != nil {
131: 			return nil, fmt.Errorf("create segment reader: %w", err)
132: 		}
133: 		defer sgmReader.Close()
134: 	}
135: 
136: 	if err := DeleteTempCheckpoints(logger, w.Dir()); err != nil {
137: 		return nil, err
138: 	}
139: 
140: 	cpdir := checkpointDir(w.Dir(), to)
141: 	cpdirtmp := cpdir + checkpointTempFileSuffix
142: 
143: 	if err := os.MkdirAll(cpdirtmp, 0o777); err != nil {
144: 		return nil, fmt.Errorf("create checkpoint dir: %w", err)
145: 	}
146: 	cp, err := New(nil, nil, cpdirtmp, w.CompressionType())
147: 	if err != nil {
148: 		return nil, fmt.Errorf("open checkpoint: %w", err)
149: 	}
150: 
151: 	// Ensures that an early return caused by an error doesn't leave any tmp files.
152: 	defer func() {
153: 		cp.Close()
154: 		os.RemoveAll(cpdirtmp)
155: 	}()
156: 
157: 	r := NewReader(sgmReader)
158: 
159: 	var (
160: 		series                []record.RefSeries
161: 		samples               []record.RefSample
162: 		histogramSamples      []record.RefHistogramSample
163: 		floatHistogramSamples []record.RefFloatHistogramSample
164: 		tstones               []tombstones.Stone
165: 		exemplars             []record.RefExemplar
166: 		metadata              []record.RefMetadata
167: 		st                    = labels.NewSymbolTable() // Needed for decoding; labels do not outlive this function.
168: 		dec                   = record.NewDecoder(st, logger)
169: 		enc                   record.Encoder
170: 		buf                   []byte
171: 		recs                  [][]byte
172: 
173: 		latestMetadataMap = make(map[chunks.HeadSeriesRef]record.RefMetadata)
174: 	)
175: 	for r.Next() {
176: 		series, samples, histogramSamples, floatHistogramSamples, tstones, exemplars, metadata = series[:0], samples[:0], histogramSamples[:0], floatHistogramSamples[:0], tstones[:0], exemplars[:0], metadata[:0]
177: 
178: 		// We don't reset the buffer since we batch up multiple records
179: 		// before writing them to the checkpoint.
180: 		// Remember where the record for this iteration starts.
181: 		start := len(buf)
182: 		rec := r.Record()
183: 
184: 		switch dec.Type(rec) {
185: 		case record.Series:
186: 			series, err = dec.Series(rec, series)
187: 			if err != nil {
188: 				return nil, fmt.Errorf("decode series: %w", err)
189: 			}
190: 			// Drop irrelevant series in place.
191: 			repl := series[:0]
192: 			for _, s := range series {
193: 				if keep(s.Ref) {
194: 					repl = append(repl, s)
195: 				}
196: 			}
197: 			if len(repl) > 0 {
198: 				buf = enc.Series(repl, buf)
199: 			}
200: 			stats.TotalSeries += len(series)
201: 			stats.DroppedSeries += len(series) - len(repl)
202: 
203: 		case record.Samples:
204: 			samples, err = dec.Samples(rec, samples)
205: 			if err != nil {
206: 				return nil, fmt.Errorf("decode samples: %w", err)
207: 			}
208: 			// Drop irrelevant samples in place.
209: 			repl := samples[:0]
210: 			for _, s := range samples {
211: 				if s.T >= mint {
212: 					repl = append(repl, s)
213: 				}
214: 			}
215: 			if len(repl) > 0 {
216: 				buf = enc.Samples(repl, buf)
217: 			}
218: 			stats.TotalSamples += len(samples)
219: 			stats.DroppedSamples += len(samples) - len(repl)
220: 
221: 		case record.HistogramSamples:
222: 			histogramSamples, err = dec.HistogramSamples(rec, histogramSamples)
223: 			if err != nil {
224: 				return nil, fmt.Errorf("decode histogram samples: %w", err)
225: 			}
226: 			// Drop irrelevant histogramSamples in place.
227: 			repl := histogramSamples[:0]
228: 			for _, h := range histogramSamples {
229: 				if h.T >= mint {
230: 					repl = append(repl, h)
231: 				}
232: 			}
233: 			if len(repl) > 0 {
234: 				buf, _ = enc.HistogramSamples(repl, buf)
235: 			}
236: 			stats.TotalSamples += len(histogramSamples)
237: 			stats.DroppedSamples += len(histogramSamples) - len(repl)
238: 		case record.CustomBucketsHistogramSamples:
239: 			histogramSamples, err = dec.HistogramSamples(rec, histogramSamples)
240: 			if err != nil {
241: 				return nil, fmt.Errorf("decode histogram samples: %w", err)
242: 			}
243: 			// Drop irrelevant histogramSamples in place.
244: 			repl := histogramSamples[:0]
245: 			for _, h := range histogramSamples {
246: 				if h.T >= mint {
247: 					repl = append(repl, h)
248: 				}
249: 			}
250: 			if len(repl) > 0 {
251: 				buf = enc.CustomBucketsHistogramSamples(repl, buf)
252: 			}
253: 			stats.TotalSamples += len(histogramSamples)
254: 			stats.DroppedSamples += len(histogramSamples) - len(repl)
255: 		case record.FloatHistogramSamples:
256: 			floatHistogramSamples, err = dec.FloatHistogramSamples(rec, floatHistogramSamples)
257: 			if err != nil {
258: 				return nil, fmt.Errorf("decode float histogram samples: %w", err)
259: 			}
260: 			// Drop irrelevant floatHistogramSamples in place.
261: 			repl := floatHistogramSamples[:0]
262: 			for _, fh := range floatHistogramSamples {
263: 				if fh.T >= mint {
264: 					repl = append(repl, fh)
265: 				}
266: 			}
267: 			if len(repl) > 0 {
268: 				buf, _ = enc.FloatHistogramSamples(repl, buf)
269: 			}
270: 			stats.TotalSamples += len(floatHistogramSamples)
271: 			stats.DroppedSamples += len(floatHistogramSamples) - len(repl)
272: 		case record.CustomBucketsFloatHistogramSamples:
273: 			floatHistogramSamples, err = dec.FloatHistogramSamples(rec, floatHistogramSamples)
274: 			if err != nil {
275: 				return nil, fmt.Errorf("decode float histogram samples: %w", err)
276: 			}
277: 			// Drop irrelevant floatHistogramSamples in place.
278: 			repl := floatHistogramSamples[:0]
279: 			for _, fh := range floatHistogramSamples {
280: 				if fh.T >= mint {
281: 					repl = append(repl, fh)
282: 				}
283: 			}
284: 			if len(repl) > 0 {
285: 				buf = enc.CustomBucketsFloatHistogramSamples(repl, buf)
286: 			}
287: 			stats.TotalSamples += len(floatHistogramSamples)
288: 			stats.DroppedSamples += len(floatHistogramSamples) - len(repl)
289: 		case record.Tombstones:
290: 			tstones, err = dec.Tombstones(rec, tstones)
291: 			if err != nil {
292: 				return nil, fmt.Errorf("decode deletes: %w", err)
293: 			}
294: 			// Drop irrelevant tombstones in place.
295: 			repl := tstones[:0]
296: 			for _, s := range tstones {
297: 				for _, iv := range s.Intervals {
298: 					if iv.Maxt >= mint {
299: 						repl = append(repl, s)
300: 						break
301: 					}
302: 				}
303: 			}
304: 			if len(repl) > 0 {
305: 				buf = enc.Tombstones(repl, buf)
306: 			}
307: 			stats.TotalTombstones += len(tstones)
308: 			stats.DroppedTombstones += len(tstones) - len(repl)
309: 
310: 		case record.Exemplars:
311: 			exemplars, err = dec.Exemplars(rec, exemplars)
312: 			if err != nil {
313: 				return nil, fmt.Errorf("decode exemplars: %w", err)
314: 			}
315: 			// Drop irrelevant exemplars in place.
316: 			repl := exemplars[:0]
317: 			for _, e := range exemplars {
318: 				if e.T >= mint {
319: 					repl = append(repl, e)
320: 				}
321: 			}
322: 			if len(repl) > 0 {
323: 				buf = enc.Exemplars(repl, buf)
324: 			}
325: 			stats.TotalExemplars += len(exemplars)
326: 			stats.DroppedExemplars += len(exemplars) - len(repl)
327: 		case record.Metadata:
328: 			metadata, err := dec.Metadata(rec, metadata)
329: 			if err != nil {
330: 				return nil, fmt.Errorf("decode metadata: %w", err)
331: 			}
332: 			// Only keep reference to the latest found metadata for each refID.
333: 			repl := 0
334: 			for _, m := range metadata {
335: 				if keep(m.Ref) {
336: 					if _, ok := latestMetadataMap[m.Ref]; !ok {
337: 						repl++
338: 					}
339: 					latestMetadataMap[m.Ref] = m
340: 				}
341: 			}
342: 			stats.TotalMetadata += len(metadata)
343: 			stats.DroppedMetadata += len(metadata) - repl
344: 		default:
345: 			// Unknown record type, probably from a future Prometheus version.
346: 			continue
347: 		}
348: 		if len(buf[start:]) == 0 {
349: 			continue // All contents discarded.
350: 		}
351: 		recs = append(recs, buf[start:])
352: 
353: 		// Flush records in 1 MB increments.
354: 		if len(buf) > 1*1024*1024 {
355: 			if err := cp.Log(recs...); err != nil {
356: 				return nil, fmt.Errorf("flush records: %w", err)
357: 			}
358: 			buf, recs = buf[:0], recs[:0]
359: 		}
360: 	}
361: 	// If we hit any corruption during checkpointing, repairing is not an option.
362: 	// The head won't know which series records are lost.
363: 	if r.Err() != nil {
364: 		return nil, fmt.Errorf("read segments: %w", r.Err())
365: 	}
366: 
367: 	// Flush remaining records.
368: 	if err := cp.Log(recs...); err != nil {
369: 		return nil, fmt.Errorf("flush records: %w", err)
370: 	}
371: 
372: 	// Flush latest metadata records for each series.
373: 	if len(latestMetadataMap) > 0 {
374: 		latestMetadata := make([]record.RefMetadata, 0, len(latestMetadataMap))
375: 		for _, m := range latestMetadataMap {
376: 			latestMetadata = append(latestMetadata, m)
377: 		}
378: 		if err := cp.Log(enc.Metadata(latestMetadata, buf[:0])); err != nil {
379: 			return nil, fmt.Errorf("flush metadata records: %w", err)
380: 		}
381: 	}
382: 
383: 	if err := cp.Close(); err != nil {
384: 		return nil, fmt.Errorf("close checkpoint: %w", err)
385: 	}
386: 
387: 	// Sync temporary directory before rename.
388: 	df, err := fileutil.OpenDir(cpdirtmp)
389: 	if err != nil {
390: 		return nil, fmt.Errorf("open temporary checkpoint directory: %w", err)
391: 	}
392: 	if err := df.Sync(); err != nil {
393: 		df.Close()
394: 		return nil, fmt.Errorf("sync temporary checkpoint directory: %w", err)
395: 	}
396: 	if err = df.Close(); err != nil {
397: 		return nil, fmt.Errorf("close temporary checkpoint directory: %w", err)
398: 	}
399: 
400: 	if err := fileutil.Replace(cpdirtmp, cpdir); err != nil {
401: 		return nil, fmt.Errorf("rename checkpoint directory: %w", err)
402: 	}
403: 
404: 	return stats, nil
405: }
