407: // checkpointPrefix is the prefix used for checkpoint files.
408: const checkpointPrefix = "checkpoint."
409: 
410: func checkpointDir(dir string, i int) string {
411: 	return filepath.Join(dir, fmt.Sprintf(checkpointPrefix+"%08d", i))
412: }
413: 
414: type checkpointRef struct {
415: 	name  string
416: 	index int
417: }
418: 
419: func listCheckpoints(dir string) (refs []checkpointRef, err error) {
420: 	files, err := os.ReadDir(dir)
421: 	if err != nil {
422: 		return nil, err
423: 	}
424: 
425: 	for i := range files {
426: 		fi := files[i]
427: 		if !strings.HasPrefix(fi.Name(), checkpointPrefix) {
428: 			continue
429: 		}
430: 		if !fi.IsDir() {
431: 			return nil, fmt.Errorf("checkpoint %s is not a directory", fi.Name())
432: 		}
433: 		idx, err := strconv.Atoi(fi.Name()[len(checkpointPrefix):])
434: 		if err != nil {
435: 			continue
436: 		}
437: 
438: 		refs = append(refs, checkpointRef{name: fi.Name(), index: idx})
439: 	}
440: 
441: 	slices.SortFunc(refs, func(a, b checkpointRef) int {
442: 		return a.index - b.index
443: 	})
444: 
445: 	return refs, nil
446: }
447: 
448: func isTempDir(fi fs.DirEntry) bool {
449: 	return strings.HasPrefix(fi.Name(), checkpointPrefix) && strings.HasSuffix(fi.Name(), checkpointTempFileSuffix)
450: }
