27: // Reader reads WAL records from an io.Reader.
28: type Reader struct {
29: 	rdr io.Reader
30: 	err error
31: 	rec []byte
32: 
33: 	precomprBuf []byte
34: 	decBuf      compression.DecodeBuffer
35: 	buf         [pageSize]byte
36: 	total       int64   // Total bytes processed.
37: 	curRecTyp   recType // Used for checking that the last record is not torn.
38: }
39: 
40: // NewReader returns a new reader.
41: func NewReader(r io.Reader) *Reader {
42: 	return &Reader{rdr: r, decBuf: compression.NewSyncDecodeBuffer()}
43: }
44: 
45: // Next advances the reader to the next records and returns true if it exists.
46: // It must not be called again after it returned false.
47: func (r *Reader) Next() bool {
48: 	err := r.nextNew()
49: 	if err != nil && errors.Is(err, io.EOF) {
50: 		// The last WAL segment record shouldn't be torn(should be full or last).
51: 		// The last record would be torn after a crash just before
52: 		// the last record part could be persisted to disk.
53: 		if r.curRecTyp == recFirst || r.curRecTyp == recMiddle {
54: 			r.err = errors.New("last record is torn")
55: 		}
56: 		return false
57: 	}
58: 	r.err = err
59: 	return r.err == nil
60: }
61: 
62: func (r *Reader) nextNew() (err error) {
63: 	// We have to use r.buf since allocating byte arrays here fails escape
64: 	// analysis and ends up on the heap, even though it seemingly should not.
65: 	hdr := r.buf[:recordHeaderSize]
66: 	buf := r.buf[recordHeaderSize:]
67: 
68: 	r.precomprBuf = r.precomprBuf[:0]
69: 
70: 	i := 0
71: 	for {
72: 		if _, err = io.ReadFull(r.rdr, hdr[:1]); err != nil {
73: 			return fmt.Errorf("read first header byte: %w", err)
74: 		}
75: 		r.total++
76: 		r.curRecTyp = recTypeFromHeader(hdr[0])
77: 
78: 		compr := compression.None
79: 		if hdr[0]&snappyMask == snappyMask {
80: 			compr = compression.Snappy
81: 		} else if hdr[0]&zstdMask == zstdMask {
82: 			compr = compression.Zstd
83: 		}
84: 
85: 		// Gobble up zero bytes.
86: 		if r.curRecTyp == recPageTerm {
87: 			// recPageTerm is a single byte that indicates the rest of the page is padded.
88: 			// If it's the first byte in a page, buf is too small and
89: 			// needs to be resized to fit pageSize-1 bytes.
90: 			buf = r.buf[1:]
91: 
92: 			// We are pedantic and check whether the zeros are actually up
93: 			// to a page boundary.
94: 			// It's not strictly necessary but may catch sketchy state early.
95: 			k := pageSize - (r.total % pageSize)
96: 			if k == pageSize {
97: 				continue // Initial 0 byte was last page byte.
98: 			}
99: 			n, err := io.ReadFull(r.rdr, buf[:k])
100: 			if err != nil {
101: 				return fmt.Errorf("read remaining zeros: %w", err)
102: 			}
103: 			r.total += int64(n)
104: 
105: 			for _, c := range buf[:k] {
106: 				if c != 0 {
107: 					return errors.New("unexpected non-zero byte in padded page")
108: 				}
109: 			}
110: 			continue
111: 		}
112: 		n, err := io.ReadFull(r.rdr, hdr[1:])
113: 		if err != nil {
114: 			return fmt.Errorf("read remaining header: %w", err)
115: 		}
116: 		r.total += int64(n)
117: 
118: 		var (
119: 			length = binary.BigEndian.Uint16(hdr[1:])
120: 			crc    = binary.BigEndian.Uint32(hdr[3:])
121: 		)
122: 
123: 		if length > pageSize-recordHeaderSize {
124: 			return fmt.Errorf("invalid record size %d", length)
125: 		}
126: 		n, err = io.ReadFull(r.rdr, buf[:length])
127: 		if err != nil {
128: 			return err
129: 		}
130: 		r.total += int64(n)
131: 
132: 		if n != int(length) {
133: 			return fmt.Errorf("invalid size: expected %d, got %d", length, n)
134: 		}
135: 		if c := crc32.Checksum(buf[:length], castagnoliTable); c != crc {
136: 			return fmt.Errorf("unexpected checksum %x, expected %x", c, crc)
137: 		}
138: 		if err := validateRecord(r.curRecTyp, i); err != nil {
139: 			return err
140: 		}
141: 
142: 		r.precomprBuf = append(r.precomprBuf, buf[:length]...)
143: 		if r.curRecTyp == recLast || r.curRecTyp == recFull {
144: 			r.rec, err = compression.Decode(compr, r.precomprBuf, r.decBuf)
145: 			return err
146: 		}
147: 
148: 		// Only increment i for non-zero records since we use it
149: 		// to determine valid content record sequences.
150: 		i++
151: 	}
152: }
