154: // Err returns the last encountered error wrapped in a corruption error.
155: // If the reader does not allow to infer a segment index and offset, a total
156: // offset in the reader stream will be provided.
157: func (r *Reader) Err() error {
158: 	if r.err == nil {
159: 		return nil
160: 	}
161: 	if b, ok := r.rdr.(*segmentBufReader); ok {
162: 		return &CorruptionErr{
163: 			Err:     r.err,
164: 			Dir:     b.segs[b.cur].Dir(),
165: 			Segment: b.segs[b.cur].Index(),
166: 			Offset:  int64(b.off),
167: 		}
168: 	}
169: 	return &CorruptionErr{
170: 		Err:     r.err,
171: 		Segment: -1,
172: 		Offset:  r.total,
173: 	}
174: }
175: 
176: // Record returns the current record. The returned byte slice is only
177: // valid until the next call to Next.
178: func (r *Reader) Record() []byte {
179: 	return r.rec
180: }
181: 
182: // Segment returns the current segment being read.
183: func (r *Reader) Segment() int {
184: 	if b, ok := r.rdr.(*segmentBufReader); ok {
185: 		return b.segs[b.cur].Index()
186: 	}
187: 	return -1
188: }
189: 
190: // Offset returns the current position of the segment being read.
191: func (r *Reader) Offset() int64 {
192: 	if b, ok := r.rdr.(*segmentBufReader); ok {
193: 		return int64(b.off)
194: 	}
195: 	return r.total
196: }
